// directory is assumed. If the cleaned request path is deemed
// not local according to lexical processing (i.e. ignoring links),
// it will be rejected as unsafe and only the root will be returned.
func SanitizedPathJoin(root, reqPath string) string {
	if root == "" {
		root = "."
	}

	relPath := path.Clean("/" + reqPath)[1:] // clean path and trim the leading /
	if relPath != "" && !filepath.IsLocal(relPath) {
		// path is unsafe (see https://github.com/golang/go/issues/56336#issuecomment-1416214885)
		return root
	}

	path := filepath.Join(root, filepath.FromSlash(relPath))

	// filepath.Join also cleans the path, and cleaning strips
	// the trailing slash, so we need to re-add it afterwards.
	// if the length is 1, then it's a path to the root,
	// and that should return ".", so we don't append the separator.
	if strings.HasSuffix(reqPath, "/") && len(reqPath) > 1 {
		path += separator
	}

	return path
}

// calculateStep determines the query step for Loki queries.
func calculateStep(interval time.Duration, timeRange time.Duration, resolution int64, queryStep *string) (time.Duration, error) {
	if queryStep == nil || *queryStep == "" {
		step := time.Duration(interval.Nanoseconds() * resolution)
		safeStep := timeRange / 11000
		chosenStep := durationMax(step, safeStep)
		return ceilMs(chosenStep), nil
	}
	step, err := gtime.ParseIntervalStringToTimeDuration(*queryStep)
	if err != nil {
		return step, backend.DownstreamError(fmt.Errorf("failed to parse query step: %w", err))
	}
	return time.Duration(step.Nanoseconds() * resolution), nil
}

func ceilMs(duration time.Duration) time.Duration {
	floatMs := float64(duration.Nanoseconds()) / 1000.0 / 1000.0
	ceilMs := math.Ceil(floatMs)
	return time.Duration(ceilMs) * time.Millisecond
}

// MatchWithError returns true if r matches m.
func (m MatchClientIP) MatchWithError(r *http.Request) (bool, error) {
	// if handshake is not finished, we infer 0-RTT that has
	// not verified remote IP; could be spoofed, so we throw
	// HTTP 425 status to tell the client to try again after
	// the handshake is complete
	if r.TLS != nil && !r.TLS.HandshakeComplete {
		return false, Error(http.StatusTooEarly, fmt.Errorf("TLS handshake not complete, remote IP cannot be verified"))
	}

	address := GetVar(r.Context(), ClientIPVarKey).(string)
	clientIP, zoneID, err := parseIPZoneFromString(address)
	if err != nil {
		m.logger.Error("getting client IP", zap.Error(err))
		return false, nil
	}
	matches, zoneFilter := matchIPByCidrZones(clientIP, zoneID, m.cidrs, m.zones)
	if !matches && !zoneFilter {
		m.logger.Debug("zone ID from client IP did not match", zap.String("zone", zoneID))
	}
	return matches, nil
}

if curveID := hs.serverHello.selectedGroup; curveID != 0 {
	if !slices.Contains(hello.supportedCurves, curveID) {
		c.sendAlert(alertIllegalParameter)
		return errors.New("tls: server selected unsupported group")
	}
	if slices.ContainsFunc(hs.hello.keyShares, func(ks keyShare) bool {
		return ks.group == curveID
	}) {
		c.sendAlert(alertIllegalParameter)
		return errors.New("tls: server sent an unnecessary HelloRetryRequest key_share")
	}
	ke, err := keyExchangeForCurveID(curveID)
	if err != nil {
		c.sendAlert(alertInternalError)
		return errors.New("tls: internal error: supportsCurve accepted unimplemented curve")
	}
	hs.keyShareKeys, hello.keyShares, err = ke.keyShares(c.config.rand())
	if err != nil {
		c.sendAlert(alertInternalError)
		return err
	}
	// Do not send the fallback ECDH key share in a HRR response.
	hello.keyShares = hello.keyShares[:1]
}

switch e := n.(type) {
case *ast.Ident:
	if e.Obj == nil && e.Name != "_" {
		unresolved[e.Name] = true
	} else if d := topDecls[e.Obj]; d != nil {

		usedObjs[e.Obj] = true
		if !usedDecls[d] {
			usedDecls[d] = true
			depDecls = append(depDecls, d)
		}
	}
	return true
case *ast.SelectorExpr:
	// For selector expressions, only inspect the left hand side.
	// (For an expression like fmt.Println, only add "fmt" to the
	// set of unresolved names, not "Println".)
	ast.Inspect(e.X, inspectFunc)
	return false
case *ast.KeyValueExpr:
	// For key value expressions, only inspect the value
	// as the key should be resolved by the type of the
	// composite literal.
	ast.Inspect(e.Value, inspectFunc)
	return false
}

