if err := webhook.WithExponentialBackoff(ctx, w.retryBackoff, func() error {
	var tokenReviewErr error
	var statusCode int

	start := time.Now()
	result, statusCode, tokenReviewErr = w.tokenReview.Create(ctx, r, metav1.CreateOptions{})
	latency := time.Since(start)

	if statusCode != 0 {
		w.metrics.RecordRequestTotal(ctx, strconv.Itoa(statusCode))
		w.metrics.RecordRequestLatency(ctx, strconv.Itoa(statusCode), latency.Seconds())
		return tokenReviewErr
	}

	if tokenReviewErr != nil {
		w.metrics.RecordRequestTotal(ctx, "<error>")
		w.metrics.RecordRequestLatency(ctx, "<error>", latency.Seconds())
	}
	return tokenReviewErr
}, webhook.DefaultShouldRetry); err != nil {
	// An error here indicates bad configuration or an outage. Log for debugging.
	klog.Errorf("Failed to make webhook authenticator request: %v", err)
	return nil, false, err
}

for _, value := range input {
	var result reflect.Value
	value, isNil := template.Indirect(value)
	if isNil {
		continue
	}

	if value.Kind() == reflect.Struct {
		var err error
		if result, err = j.findFieldInValue(&value, node); err != nil {
			return nil, err
		}
	} else if value.Kind() == reflect.Map {
		mapKeyType := value.Type().Key()
		nodeValue := reflect.ValueOf(node.Value)
		// node value type must be convertible to map key type
		if !nodeValue.Type().ConvertibleTo(mapKeyType) {
			return results, fmt.Errorf("%s is not convertible to %s", nodeValue, mapKeyType)
		}
		result = value.MapIndex(nodeValue.Convert(mapKeyType))
	}
	if result.IsValid() {
		results = append(results, result)
	}
}

for _, apiGroup := range apiGroups.Groups {
	for _, version := range apiGroup.Versions {
		groupVersion := schema.GroupVersion{Group: apiGroup.Name, Version: version.Version}
		wg.Add(1)
		go func() {
			defer wg.Done()
			defer utilruntime.HandleCrash()

			apiResourceList, err := d.ServerResourcesForGroupVersion(groupVersion.String())

			// lock to record results
			resultLock.Lock()
			defer resultLock.Unlock()

			if err != nil {
				// TODO: maybe restrict this to NotFound errors
				failedGroups[groupVersion] = err
			}
			if apiResourceList != nil {
				// even in case of error, some fallback might have been returned
				groupVersionResources[groupVersion] = apiResourceList
			}
		}()
	}
}

if schema.Type() == "array" {
	l, ok := unstructured.([]interface{})
	if !ok {
		return types.NewErr("invalid data, expected an array for the provided schema with type=array")
	}
	if schema.Items() == nil {
		return types.NewErr("invalid array type, expected Items with a non-empty Schema")
	}
	typedList := unstructuredList{elements: l, itemsSchema: schema.Items()}
	listType := schema.XListType()
	if listType != "" {
		switch listType {
		case "map":
			mapKeys := schema.XListMapKeys()
			return &unstructuredMapList{unstructuredList: typedList, escapedKeyProps: escapeKeyProps(mapKeys)}
		case "set":
			return &unstructuredSetList{unstructuredList: typedList}
		case "atomic":
			return &typedList
		default:
			return types.NewErr("invalid x-kubernetes-list-type, expected 'map', 'set' or 'atomic' but got %s", listType)
		}
	}
	return &typedList
}

switch t.(type) {
case swarm.Node:
	res, err := r.client.NodeInspect(ctx, id, client.NodeInspectOptions{})
	if err != nil {
		// TODO(thaJeztah): should error-handling be more specific, or is it ok to ignore any error?
		return id, nil //nolint:nilerr // ignore nil-error being returned, as this is a best-effort.
	}
	if res.Node.Spec.Annotations.Name != "" {
		return res.Node.Spec.Annotations.Name, nil
