if len(oldTsDir) != 0 {
	// (3)
	pathsToRemove, err = w.pathsToRemove(cleanPayload, oldTsPath)
	if err != nil {
		klog.Errorf("%s: error determining user-visible files to remove: %v", w.logContext, err)
		return err
	}

	// (4)
	if should, err := shouldWritePayload(cleanPayload, oldTsPath); err != nil {
		klog.Errorf("%s: error determining whether payload should be written to disk: %v", w.logContext, err)
		return err
	} else if !should && len(pathsToRemove) == 0 {
		klog.V(4).Infof("%s: write not required for data directory %v", w.logContext, oldTsDir)
		// data directory is already up to date, but we need to make sure that
		// the user-visible symlinks are created.
		// See https://github.com/kubernetes/kubernetes/issues/121472 for more details.
		// Reset oldTsDir to empty string to avoid removing the data directory.
		shouldWrite = false
		oldTsDir = ""
	} else {
		klog.V(4).Infof("%s: write required for target directory %v", w.logContext, w.targetDir)
	}
}

switch {
case len(mapping.Expression) > 0 && len(mapping.Claim) > 0:
	allErrs = append(allErrs, field.Invalid(fldPath, "", "claim and expression can't both be set"))
case len(mapping.Expression) == 0 && len(mapping.Claim) == 0 && claimOrExpressionRequired:
	allErrs = append(allErrs, field.Required(fldPath, "claim or expression is required"))
case len(mapping.Expression) > 0:
	var err *field.Error

	if mapping.Prefix != nil {
		allErrs = append(allErrs, field.Invalid(fldPath.Child("prefix"), *mapping.Prefix, "may not be specified when expression is set"))
	}
	compilationResult, err = compileClaimsCELExpression(compiler, &authenticationcel.ClaimMappingExpression{
		Expression: mapping.Expression,
	}, fldPath.Child("expression"))

	if err != nil {
		allErrs = append(allErrs, err)
	}

case len(mapping.Claim) > 0:
	if mapping.Prefix == nil {
		allErrs = append(allErrs, field.Required(fldPath.Child("prefix"), "prefix is required when claim is set. It can be set to an empty string to disable prefixing"))
	}
}

for gvk, resource := range a.AllPrunableResources() {
	scope := resource.restMapping.Scope

	switch scope.Name() {
	case meta.RESTScopeNameNamespace:
		for _, namespace := range a.AllPrunableNamespaces() {
			if namespace == "" {
				// Just double-check because otherwise we get cryptic error messages
				return nil, fmt.Errorf("unexpectedly encountered empty namespace during prune of namespace-scoped resource %v", gvk)
			}
			tasks = append(tasks, &task{
				namespace:   namespace,
				restMapping: resource.restMapping,
			})
		}

	case meta.RESTScopeNameRoot:
		tasks = append(tasks, &task{
			restMapping: resource.restMapping,
		})

	default:
		return nil, fmt.Errorf("unhandled scope %q", scope.Name())
	}
}

for gr, wroteRV := range w.versions {
	store, exists := c.stores[gr]
	if !exists || store == nil {
		continue
	}
	readRV := store.LastStoreSyncResourceVersion()
	if readRV == "" {
		// Since we wait for the store to be ready, the only time "" is if the
		// LastStoreSyncResourceVersion() feature is not enabled.
		continue
	}
	i, err := resourceversion.CompareResourceVersion(wroteRV, readRV)
	if err != nil {
		// comparison errors indicate there's a data problem with resource versions, continue so we don't block syncing
		continue
	}
	if i > 0 {
		// read version is not as new as owner version, not ready
		return &ConsistencyError{
			WroteRV:       wroteRV,
			ReadRV:        readRV,
			GroupResource: gr,
		}
	}
}

if f.knownObjects != nil {
	// Detect deletions for objects not present in the queue, but present in KnownObjects
	knownKeys := f.knownObjects.ListKeys()
	for _, k := range knownKeys {
		if keys.Has(k) {
			continue
		}
		if len(f.items[k]) > 0 {
			continue
		}

		deletedObj, exists, err := f.knownObjects.GetByKey(k)
		if err != nil {
			deletedObj = nil
			utilruntime.HandleErrorWithLogger(f.logger, err, "Unexpected error during lookup, placing DeleteFinalStateUnknown marker without object", "key", k)
		} else if !exists {
			deletedObj = nil
			f.logger.Info("Key does not exist in known objects store, placing DeleteFinalStateUnknown marker without object", "key", k)
		}
		queuedDeletions++
		if err := f.queueActionLocked(Deleted, DeletedFinalStateUnknown{k, deletedObj}); err != nil {
			return err
		}
	}
}

if h.RejectForwardingRedirects {
	oldModifyResponse := proxy.ModifyResponse
	proxy.ModifyResponse = func(response *http.Response) error {
		code := response.StatusCode
		if code >= 300 && code <= 399 && len(response.Header.Get("Location")) > 0 {
			// close the original response
			response.Body.Close()
			msg := "the backend attempted to redirect this request, which is not permitted"
			// replace the response
			*response = http.Response{
				StatusCode:    http.StatusBadGateway,
				Status:        fmt.Sprintf("%d %s", response.StatusCode, http.StatusText(response.StatusCode)),
				Body:          io.NopCloser(strings.NewReader(msg)),
				ContentLength: int64(len(msg)),
			}
		} else {
			if oldModifyResponse != nil {
				if err := oldModifyResponse(response); err != nil {
					return err
				}
			}
		}
		return nil
	}
}

for _, protocolHeader := range req.Header[protocolHeader] {
	for _, protocol := range strings.Split(protocolHeader, ",") {
		protocol = strings.TrimSpace(protocol)

		if !strings.HasPrefix(protocol, bearerProtocolPrefix) {
			filteredProtocols = append(filteredProtocols, protocol)
			continue
		}

		if sawTokenProtocol {
			return nil, false, errors.New("multiple base64.bearer.authorization tokens specified")
		}
		sawTokenProtocol = true

		encodedToken := strings.TrimPrefix(protocol, bearerProtocolPrefix)
		decodedToken, err := base64.RawURLEncoding.DecodeString(encodedToken)
		if err != nil {
			return nil, false, errors.New("invalid base64.bearer.authorization token encoding")
		}
		if !utf8.Valid(decodedToken) {
			return nil, false, errors.New("invalid base64.bearer.authorization token")
		}
		token = string(decodedToken)
	}
}

for _, hints := range providersHints {
	// If hints is nil, insert a single, preferred any-numa hint into allProviderHints.
	if len(hints) == 0 {
		logger.Info("Hint Provider has no preference for NUMA affinity with any resource")
		allProviderHints = append(allProviderHints, []TopologyHint{{nil, true}})
		continue
	}

	// Otherwise, accumulate the hints for each resource type into allProviderHints.
	for resource := range hints {
		if hints[resource] == nil {
			logger.Info("Hint Provider has no preference for NUMA affinity with resource", "resource", resource)
			allProviderHints = append(allProviderHints, []TopologyHint{{nil, true}})
			continue
		}

		if len(hints[resource]) == 0 {
			logger.Info("Hint Provider has no possible NUMA affinities for resource", "resource", resource)
			allProviderHints = append(allProviderHints, []TopologyHint{{nil, false}})
			continue
		}

		allProviderHints = append(allProviderHints, hints[resource])
	}
}

for _, groupVersionKind := range gvks {
	gvk := strings.Split(groupVersionKind, "/")
	if len(gvk) != 3 {
		return nil, fmt.Errorf("invalid GroupVersionKind format: %v, please follow <group/version/kind>", groupVersionKind)
	}

	if gvk[0] == "core" {
		gvk[0] = ""
	}
	mapping, err := mapper.RESTMapping(schema.GroupKind{Group: gvk[0], Kind: gvk[2]}, gvk[1])
	if err != nil {
		return pruneResources, err
	}
	var namespaced bool
	namespaceScope := mapping.Scope.Name()
	switch namespaceScope {
	case meta.RESTScopeNameNamespace:
		namespaced = true
	case meta.RESTScopeNameRoot:
		namespaced = false
	default:
		return pruneResources, fmt.Errorf("Unknown namespace scope: %q", namespaceScope)
	}

	pruneResources = append(pruneResources, Resource{gvk[0], gvk[1], gvk[2], namespaced})
}

for _, chain := range oldTable.Chains {
	for _, rule := range chain.Rules {
		if rule.Jump == nil {
			continue
		}
		if builtinTargets.Has(rule.Jump.Value) {
			continue
		}

		jumpedChain, _ := f.Dump.GetChain(oldTable.Name, iptables.Chain(rule.Jump.Value))
		if jumpedChain == nil {
			newChain, _ := newDump.GetChain(oldTable.Name, iptables.Chain(rule.Jump.Value))
			if newChain != nil {
				// rule is an old rule that jumped to a chain which
				// was deleted by newDump.
				oldTable.Chains = backupChains
				return fmt.Errorf("deleted chain %q is referenced by existing rules", newChain.Name)
			} else {
				// rule is a new rule that jumped to a chain that was
				// neither created nor pre-existing
				oldTable.Chains = backupChains
				return fmt.Errorf("rule %q jumps to a non-existent chain", rule.Raw)
			}
		}
	}
}

for it.Next() {
	bucket := it.At()
	if bucket.Count == 0 {
		continue // No need to expose empty buckets in JSON.
	}
	boundaries := 2 // Exclusive on both sides AKA open interval.
	if bucket.LowerInclusive {
		if bucket.UpperInclusive {
			boundaries = 3 // Inclusive on both sides AKA closed interval.
		} else {
			boundaries = 1 // Inclusive only on lower end AKA right open.
		}
	} else {
		if bucket.UpperInclusive {
			boundaries = 0 // Inclusive only on upper end AKA left open.
		}
	}
	bucketToMarshal := []any{
		boundaries,
		strconv.FormatFloat(bucket.Lower, 'f', -1, 64),
		strconv.FormatFloat(bucket.Upper, 'f', -1, 64),
		strconv.FormatFloat(bucket.Count, 'f', -1, 64),
	}
	h.Buckets = append(h.Buckets, bucketToMarshal)
}

